var createTimeEntrySchema = external_exports.object({
  taskId: external_exports.string().uuid().optional(),
  projectId: external_exports.string().uuid(),
  description: external_exports.string().min(1).max(500).optional(),
  startTime: external_exports.string().datetime(),
  endTime: external_exports.string().datetime().optional(),
  duration: external_exports.number().min(0).optional(),
  // In seconds
  isBillable: external_exports.boolean().default(true),
  billableRate: external_exports.number().min(0).optional(),
  tags: external_exports.array(external_exports.string()).max(10).optional()
}).refine(
  (data) => {
    if (data.endTime) {
      return new Date(data.endTime) > new Date(data.startTime);
    }
    return true;
  },
  { message: "End time must be after start time", path: ["endTime"] }
).refine(
  (data) => {
    if (data.endTime && data.duration) {
      const calculatedDuration = (new Date(data.endTime).getTime() - new Date(data.startTime).getTime()) / 1e3;
      return Math.abs(calculatedDuration - data.duration) < 1;
    }
    return true;
  },
  { message: "Duration must match the time difference", path: ["duration"] }
).refine(
  (data) => {
    if (data.endTime) {
      const durationHours = (new Date(data.endTime).getTime() - new Date(data.startTime).getTime()) / (1e3 * 60 * 60);
      return durationHours <= 24;
    }
    if (data.duration) {
      return data.duration <= 24 * 60 * 60;
    }
    return true;
  },
  { message: "Time entry cannot exceed 24 hours", path: ["endTime"] }
);
